const queryClient=new QueryClient({defaultOptions:{queries:{staleTime:300000}}})
const rupiah=(value:number)=>value<0?`(Rp ${Math.abs(value).toLocaleString('id-ID')})`:`Rp ${value.toLocaleString('id-ID')}`
const compact=(value:number)=>`Rp ${(value/1000).toLocaleString('id-ID',{maximumFractionDigits:1})} M`
