type CompanyFilter='all'|'pt-1001'|'pt-maison'
const companies:{value:CompanyFilter;label:string;scale:number}[]=[{value:'all',label:'Semua Perusahaan',scale:1},{value:'pt-1001',label:'1001',scale:.46},{value:'pt-maison',label:'Maison',scale:.54}]
type ReportFilterState={company:CompanyFilter;month:string;year:string;setCompany:(company:CompanyFilter)=>void;setMonth:(month:string)=>void;setYear:(year:string)=>void}
const CompanyFilterContext=createContext<ReportFilterState>({company:'all',month:'Juni',year:'2026',setCompany:()=>{},setMonth:()=>{},setYear:()=>{}})
const useCompanyFilter=()=>useContext(CompanyFilterContext)
const filterCompanyToStorage=(company:CompanyFilter):'all'|'1001'|'Maison'=>company==='pt-1001'?'1001':company==='pt-maison'?'Maison':'all'
const storageCompanyToFilter=(company:'1001'|'Maison'):CompanyFilter=>company==='1001'?'pt-1001':'pt-maison'
const buildImportedRows=(rows:StoredReportRow[],reportType:'balance_sheet'|'profit_loss'):FinancialReportLine[]|null=>{if(!rows.length)return null;const grouped=Array.from(rows.reduce((map,row)=>map.set(row.category,[...(map.get(row.category)??[]),row]),new Map<string,StoredReportRow[]>())).flatMap(([category,items])=>{const total=items.reduce((a,b)=>a+b.amount,0);return [{label:category.toUpperCase(),kind:'title'},...items.sort((a,b)=>a.accountCode.localeCompare(b.accountCode)).map(row=>({label:row.accountName,value:row.amount})),{label:`TOTAL ${category.toUpperCase()}`,value:total,kind:reportType==='balance_sheet'?'grand':'total'}]});if(reportType==='balance_sheet'){const total=(cat:string)=>rows.filter(row=>row.category===cat).reduce((a,b)=>a+b.amount,0);return [...grouped,{label:'TOTAL LIABILITAS + EKUITAS',value:total('Liabilitas')+total('Ekuitas'),kind:'grand'}]}return grouped}
const useCompanyData=()=>{const {company,month,year}=useCompanyFilter();const selected=companies.find(x=>x.value===company)??companies[0];const storageCompany=filterCompanyToStorage(company);const balanceQuery=useQuery({queryKey:['neraca',storageCompany,month,year],queryFn:()=>reportDataService.getPeriod({company:storageCompany,month,year:Number(year),reportType:'balance_sheet'})});const incomeQuery=useQuery({queryKey:['laba-rugi',storageCompany,month,year],queryFn:()=>reportDataService.getPeriod({company:storageCompany,month,year:Number(year),reportType:'profit_loss'})});useEffect(()=>{const handler=()=>{queryClient.invalidateQueries({queryKey:['neraca']});queryClient.invalidateQueries({queryKey:['laba-rugi']});queryClient.invalidateQueries({queryKey:['financial-overview']});queryClient.invalidateQueries({queryKey:['kpi']});queryClient.invalidateQueries({queryKey:['dashboard']})};window.addEventListener('report-data-updated',handler);return()=>window.removeEventListener('report-data-updated',handler)},[]);return useMemo(()=>{const importedBalanceRows=buildImportedRows(balanceQuery.data??[],'balance_sheet');const importedIncomeRows=buildImportedRows(incomeQuery.data??[],'profit_loss');const scaleValue=(value:number)=>Math.round(value*selected.scale);const activeBalanceRows=importedBalanceRows??balanceRows.map(r=>r.value===undefined?r:{...r,value:scaleValue(r.value)});const activeIncomeRows=importedIncomeRows??incomeRows.map(r=>r.value===undefined?r:{...r,value:scaleValue(r.value)});const balanceStored=balanceQuery.data??[];const incomeStored=incomeQuery.data??[];const totalBy=(cat:string)=>balanceStored.filter(row=>row.category===cat).reduce((a,b)=>a+b.amount,0);const revenue=incomeStored.filter(row=>row.category==='Pendapatan').reduce((a,b)=>a+b.amount,0);const expense=incomeStored.filter(row=>!['Pendapatan','Pendapatan Lain-lain'].includes(row.category)).reduce((a,b)=>a+b.amount,0);const importedKpis=balanceStored.length?kpis.map(k=>k.label==='Total Asset'?{...k,value:totalBy('Aset')}:k.label==='Total Liabilitas'?{...k,value:totalBy('Liabilitas')}:k.label==='Total Ekuitas'?{...k,value:totalBy('Ekuitas')}:k.label==='Pendapatan'&&incomeStored.length?{...k,value:revenue}:k.label==='Beban'&&incomeStored.length?{...k,value:expense}:k):kpis.map(k=>({...k,value:scaleValue(k.value)}));return {selected,month,year,kpis:importedKpis,monthly:monthly.map(m=>({...m,revenue:scaleValue(m.revenue),expense:scaleValue(m.expense),profit:scaleValue(m.profit),cash:scaleValue(m.cash)})),departments:departments.map(d=>({...d,value:scaleValue(d.value)})),accounts:accounts.map(a=>({...a,value:scaleValue(a.value)})),balanceRows:activeBalanceRows,incomeRows:activeIncomeRows,balanceTotals:{asset:totalBy('Aset'),liability:totalBy('Liabilitas'),equity:totalBy('Ekuitas'),difference:totalBy('Aset')-(totalBy('Liabilitas')+totalBy('Ekuitas'))}}},[selected,balanceQuery.data,incomeQuery.data,month,year])}

function Filters(){const {company,setCompany,month,year}=useCompanyFilter();return <div className="card p-4 flex flex-wrap gap-3 items-end">{[['Periode','Bulanan'],['Bulan',month],['Tahun',year]].map(([l,v])=><label className="min-w-[135px] flex-1" key={l}><span className="label mb-1.5 block">{l}</span><span className="h-10 px-3 border border-slate-200 rounded-lg flex items-center justify-between text-xs font-medium text-slate-600 bg-white">{v}<ChevronDown size={14}/></span></label>)}<label className="min-w-[135px] flex-1"><span className="label mb-1.5 block">Entitas / Company</span><span className="relative h-10 border border-slate-200 rounded-lg flex items-center justify-between text-xs font-medium text-slate-600 bg-white"><select value={company} onChange={event=>setCompany(event.target.value as CompanyFilter)} className="w-full h-full px-3 pr-8 rounded-lg bg-transparent appearance-none outline-none text-xs font-medium text-slate-600">{companies.map(option=><option value={option.value} key={option.value}>{option.label}</option>)}</select><ChevronDown size={14} className="absolute right-3 pointer-events-none"/></span></label>{[['Department','Semua Department'],['Cost Center','Semua Cost Center']].map(([l,v])=><label className="min-w-[135px] flex-1" key={l}><span className="label mb-1.5 block">{l}</span><span className="h-10 px-3 border border-slate-200 rounded-lg flex items-center justify-between text-xs font-medium text-slate-600 bg-white">{v}<ChevronDown size={14}/></span></label>)}</div>}
const menu=[{name:'Dashboard',icon:LayoutDashboard,path:'/'},{name:'Laporan Keuangan',icon:Landmark,children:[['Neraca','/neraca'],['Laba Rugi','/laba-rugi'],['Arus Kas','/arus-kas']]},{name:'Budgeting',icon:Wallet,children:[['Ringkasan Budget','/budgeting'],['Budget vs Actual','/budgeting/budget-vs-actual'],['Budget per Department','/budgeting/department'],['Budget per Account','/budgeting/account'],['Upload Budget','/budgeting/upload']]},{name:'Analisa',icon:TrendingUp,children:[['Rasio Keuangan','/analisa'],['Trend Keuangan','/trend'],['Analisa Profitabilitas','/profitabilitas']]},{name:'Master Data',icon:Database,children:[['Chart of Account','/coa'],['Department','/department'],['Cost Center','/cost-center']]},{name:'Pengaturan',icon:Settings,path:'/settings'}]
